-- Demo tenant IDs
-- Restaurant: demo restaurant with one floor, mixed table shapes, staff users, menu, modifiers, and historical data.

-- Auth users (demo credentials)
-- Password for all demo users: Demo1234!
do $$
declare
  uids uuid[] := array[
    '00000000-0000-0000-0000-000000000101'::uuid,
    '00000000-0000-0000-0000-000000000102'::uuid,
    '00000000-0000-0000-0000-000000000103'::uuid,
    '00000000-0000-0000-0000-000000000104'::uuid,
    '00000000-0000-0000-0000-000000000105'::uuid,
    '00000000-0000-0000-0000-000000000106'::uuid
  ];
  emails text[] := array[
    'manager@demo-resto.com',
    'waiter1@demo-resto.com',
    'waiter2@demo-resto.com',
    'kitchen@demo-resto.com',
    'cashier@demo-resto.com',
    'superadmin@demo-resto.com'
  ];
  names text[] := array[
    'Laura Manager',
    'Marco Waiter',
    'Sofia Waiter',
    'Daniel Kitchen',
    'Eva Cashier',
    'Global Admin'
  ];
  i int;
  uid uuid;
  email text;
  name text;
begin
  for i in 1..array_length(uids, 1) loop
    uid := uids[i];
    email := emails[i];
    name := names[i];

    if not exists (select 1 from auth.users where id = uid) then
      insert into auth.users (
        instance_id,
        id,
        aud,
        role,
        email,
        encrypted_password,
        email_confirmed_at,
        raw_app_meta_data,
        raw_user_meta_data,
        created_at,
        updated_at,
        is_anonymous
      )
      values (
        '00000000-0000-0000-0000-000000000000',
        uid,
        'authenticated',
        'authenticated',
        email,
        crypt('Demo1234!', gen_salt('bf')),
        now(),
        '{"provider":"email","providers":["email"]}'::jsonb,
        jsonb_build_object('full_name', name),
        now(),
        now(),
        false
      );
    end if;

    if not exists (
      select 1 from auth.identities where user_id = uid and provider = 'email'
    ) then
      insert into auth.identities (
        id,
        user_id,
        identity_data,
        provider,
        provider_id,
        last_sign_in_at,
        created_at,
        updated_at
      )
      values (
        gen_random_uuid(),
        uid,
        jsonb_build_object(
          'sub', uid::text,
          'email', email,
          'email_verified', true,
          'full_name', name
        ),
        'email',
        uid::text,
        now(),
        now(),
        now()
      );
    end if;
  end loop;
end $$;

